import machine
import socket
import json
import ssl

# Set up SSL context
context = ssl.create_default_context(ssl.Purpose.CLIENT_AUTH)
context.load_cert_chain('cert.pem', 'key.pem')

# Create a WebSocket server
ws_server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)

# Wrap the socket with SSL
ws_server = context.wrap_socket(ws_server, server_side=True)

# Bind to address and port
ws_server.bind(('0.0.0.0', 8080))
ws_server.listen(1)

print('WebSocket server listening on port 8080...')

while True:
    # Accept incoming connections
    conn, addr = ws_server.accept()

    print(f'New connection from {addr}')

    try:
        # Handle WebSocket protocol
        with conn:
            while True:
                data = conn.recv(1024)
                if not data:
                    break

                # Parse JSON command
                try:
                    cmd = json.loads(data.decode())
                except ValueError:
                    print('Invalid JSON command')
                    continue

                # Handle action
                if 'action' in cmd:
                    if cmd['action'] == 'turn_on':
                        # Turn on device (replace with actual logic)
                        print('Turning on device...')
                    elif cmd['action'] == 'turn_off':
                        # Turn off device (replace with actual logic)
                        print('Turning off device...')

                # Send response back to client
                conn.sendall(b'{"status": "ok"}')
    except Exception as e:
        print(f'Error handling connection: {e}')

# Close the WebSocket server
ws_server.close()